package io.jenkins.plugins.jobcacher.oras;

import java.nio.charset.StandardCharsets;
import java.util.Base64;

public final class Logo {

    /**
     * The logo from /images/jobcacher-oras.png
     */
    public static final String LOGO_BASE_64 =
            "";

    /**
     * Name of the logo
     */
    public static final String LOGO_NAME = "jobcacher-oras.png";

    /**
     * Return the decoded logo as bytes array
     * @return The decoded logo
     */
    public static byte[] getDecodedLogo() {
        return Base64.getDecoder().decode(LOGO_BASE_64.getBytes(StandardCharsets.UTF_8));
    }
}
